def solve(deps: dict[str, list[str]]) -> list[list[str]]:
    nodes = set(deps.keys())
    for prereqs in deps.values():
        nodes.update(prereqs)

    in_degree = {node: 0 for node in nodes}
    adj = {node: [] for node in nodes}

    for task, prereqs in deps.items():
        for p in prereqs:
            adj[p].append(task)
            in_degree[task] += 1

    result = []
    current_layer = sorted([node for node, degree in in_degree.items() if degree == 0])

    while current_layer:
        result.append(current_layer)
        next_layer = []
        for node in current_layer:
            for neighbor in adj[node]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    next_layer.append(neighbor)
        current_layer = sorted(next_layer)

    if sum(len(layer) for layer in result) != len(nodes):
        return []
    return result
