def solve(capacity: int, ops: list[str]) -> list[int]:
    cache = OrderedDict()
    res = []
    for op in ops:
        parts = op.split()
        if parts[0] == "get":
            key = int(parts[1])
            if capacity == 0:
                res.append(-1)
            elif key in cache:
                cache.move_to_end(key)
                res.append(cache[key])
            else:
                res.append(-1)
        elif parts[0] == "put":
            key = int(parts[1])
            value = int(parts[2])
            if capacity == 0:
                continue
            if key in cache:
                cache.move_to_end(key)
            else:
                if len(cache) == capacity:
                    cache.popitem(last=False)
            cache[key] = value
    return res
