import bisect

def solve(nums: list[int], k: int) -> list[float]:
    if not nums or k == 0:
        return []

    window = sorted(nums[:k])
    res = []
    mid = k // 2

    if k % 2 == 1:
        res.append(float(window[mid]))
    else:
        res.append((window[mid - 1] + window[mid]) / 2.0)

    for i in range(k, len(nums)):
        out_num = nums[i - k]
        in_num = nums[i]

        idx = bisect.bisect_left(window, out_num)
        window.pop(idx)
        bisect.insort(window, in_num)

        if k % 2 == 1:
            res.append(float(window[mid]))
        else:
            res.append((window[mid - 1] + window[mid]) / 2.0)

    return res

