def solve(deps: dict[str, list[str]], changed: list[str]) -> list[str]:
    rev_deps = {}
    for pkg, dependencies in deps.items():
        for dep in dependencies:
            rev_deps.setdefault(dep, []).append(pkg)

    affected = set(changed)
    queue = deque(changed)

    while queue:
        curr = queue.popleft()
        for pkg in rev_deps.get(curr, []):
